<?php require_once __DIR__ . '/../includes/db.php'; if(!logged_in()) redirect_to('auth/login.php'); $cart=$_SESSION['cart']??[]; if(empty($cart)) redirect_to('cart/index.php'); $subtotal=0; foreach($cart as $id=>$qty){ $r=mysqli_query($conn,'SELECT price FROM products WHERE id='.(int)$id); if($p=mysqli_fetch_assoc($r)) $subtotal+=$p['price']*$qty; } $total=$subtotal*1.07; $uid=(int)$_SESSION['user_id']; $pm=mysqli_real_escape_string($conn,$_POST['payment_method']??'Card'); mysqli_query($conn,"INSERT INTO orders(user_id,total,payment_method,payment_status,status) VALUES($uid,$total,'$pm','Paid','Processing')"); $order_id=mysqli_insert_id($conn); foreach($cart as $id=>$qty){ $r=mysqli_query($conn,'SELECT price FROM products WHERE id='.(int)$id); if($p=mysqli_fetch_assoc($r)){ $price=(float)$p['price']; mysqli_query($conn,'INSERT INTO order_items(order_id,product_id,quantity,price) VALUES('.$order_id.','.(int)$id.','.(int)$qty.','.$price.')'); }} unset($_SESSION['cart']); redirect_to('orders/confirmation.php?id='.$order_id); ?>